ps.pstext:
if !IsFeatureImplemented(FEAT_SVE) then EndOfDecode(Decode_UNDEF); end;
let t : integer = UInt(Zt);
let n : integer = UInt(Zn);
let g : integer = UInt(Pg);
let esize : integer{} = 64;
let msize : integer{} = 64;
let unsigned : boolean = TRUE;
let offset : integer = UInt(imm5);

CheckNonStreamingSVEEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV esize;
let mask : bits(PL) = P{}(g);
var base : bits(VL);
var result : bits(VL);
var data : bits(msize);
let mbytes : integer{} = msize DIV 8;
let contiguous : boolean = FALSE;
let nontemporal : boolean = FALSE;
let predicated : boolean = TRUE;
let tagchecked : boolean = TRUE;
let accdesc : AccessDescriptor = CreateAccDescSVE(MemOp_LOAD, nontemporal, contiguous,
                                                     predicated, tagchecked);

if AnyActiveElement{PL}(mask, esize) then
    base = Z{VL}(n);
end;

for e = 0 to elements-1 do
    if ActivePredicateElement{PL}(mask, e, esize) then
        let baddr : bits(64) = ZeroExtend{}(base[e*:esize]);
        let addr : bits(64) = AddressAdd(baddr, offset * mbytes, accdesc);
        data = Mem{msize}(addr, accdesc);
        result[e*:esize] = Extend{esize}(data, unsigned);
    else
        result[e*:esize] = Zeros{esize};
    end;
end;

Z{VL}(t) = result;
